import { Component, OnInit } from '@angular/core';

import { MatDialog } from '@angular/material/dialog';
import { ApiService } from '../../core/services/api.service';

import { WaitSpinnerComponent } from '../../shared/wait-spinner/wait-spinner.component';

import { ProjectModel, PaginatedItemsModel } from '../../core/models/server/models';
import { ProjectDetails } from '../../core/models/project.model';
import { PageSizeRange } from './projects-filter/projects-filter.component';


type Filter = {
  search: string,
  fromDate: string,
  toDate: string,
  ordering: string,
  asc: boolean,
  page: number,
  page_size: PageSizeRange
};
type Message = { type: 'danger' | 'success', header: string, body: string };


@Component({
  selector: 'app-projects',
  templateUrl: './projects.component.html',
  styleUrls: ['./projects.component.scss']
})
export class ProjectsComponent implements OnInit {
  public readonly Ordering = {
    project: 'name',
    creationDate: 'created_on'
  };

  private resultMessageTimeout: any;

  public isListView = true;
  public viewMode: 'grid' | 'list';
  public projectsPageResult: PaginatedItemsModel<ProjectModel>;
  public projects: ProjectModel[] = [];
  public projectsDetails: ProjectDetails[] = [];
  public resultMessage: Message;

  public dateFilterMessage: string;
  public filter: Filter = {
    search: '',
    fromDate: '',
    toDate: '',
    ordering: '',
    asc: true,
    page: 1,
    page_size: 20
  };


  constructor(
    private matDialogService: MatDialog,
    private apiService: ApiService
  ) { }

  ngOnInit() {
    this.changeViewMode('grid');
  }

  public changeViewMode(mode: 'grid' | 'list'): void {
    if (this.viewMode === mode) {
      return;
    }

    this.isListView = mode === 'list';
    this.viewMode = mode;
    this.filter = {
      search: '',
      fromDate: '',
      toDate: '',
      ordering: '',
      asc: true,
      page: 1,
      page_size: this.isListView ? 20 : 'all'
    };
    this.fetchProjects();
  }

  private async fetchProjects(): Promise<void> {
    this.dateFilterMessage = undefined;
    this.clearProjects();
    this.closeMessage();
    const dialogRef = this.matDialogService.open(WaitSpinnerComponent, { disableClose: true });

    try {
      const F = this.filter;
      const pageResult = await this.apiService.projects__get(F.search, F.fromDate, F.toDate, F.ordering, F.asc, F.page, F.page_size);
      this.setProjects(pageResult);

      if (this.filter.fromDate) {
        this.dateFilterMessage = `Projects Creation Date Filtered From <b>${this.filter.fromDate}</b> To <b>${this.filter.toDate}</b>`;
      }
    } catch (error) {
      this.showMessage({
        type: 'danger', header: '<strong>Error Fetching Data</strong><hr>',
        body: 'Something went wrong while fetching your projects.'
      }, 5000);
    } finally {
      dialogRef.close();
    }
  }

  private setProjects(projectsPageResult: PaginatedItemsModel<ProjectModel>): void {
    this.projectsPageResult = projectsPageResult;
    this.projects = projectsPageResult.results;

    if (!this.isListView) {
      this.setProjectsDetails();
    }
  }

  private clearProjects(): void {
    this.projectsPageResult = undefined;
    this.projects = [];
    this.projectsDetails = [];
  }

  private setProjectsDetails(): void {
    this.projectsDetails = [];

    for (const project of this.projects) {
      this.projectsDetails.push({
        title: project.name,
        address: {
          part1: project.address_line_1,
          part2: `${project.city}, ${project.state}, ${project.zip}`
        },
        estimator: project.estimator,
        tech: project.tech,
        passedSteps: project.passedSteps
      });
    }
  }

  private showMessage(message: Message, timeout?: number): void {
    this.closeMessage();
    this.resultMessage = message;
    if (timeout) {
      this.resultMessageTimeout = setTimeout(() => this.closeMessage(), timeout);
    }
  }

  public closeMessage(): void {
    clearTimeout(this.resultMessageTimeout);
    this.resultMessage = undefined;
  }

  // app-projects-filter --------------------------------------------------------------------------
  public onDateChange(value: { from: string, to: string }): void {
    // Check if changed
    if (this.filter.fromDate === value.from && this.filter.toDate === value.to) {
      return;
    }

    // Set filter properties
    this.filter.fromDate = value.from;
    this.filter.toDate = value.to;
    this.filter.page = 1;

    // Fetch projects with filter
    this.fetchProjects();
  }

  public onSearchChange(value: string): void {
    // Check if changed
    if (this.filter.search === value) {
      return;
    }

    // Set filter properties
    this.filter.search = value;
    this.filter.page = 1;

    // Fetch projects with filter
    this.fetchProjects();
  }

  public onPageSizeChange(value: PageSizeRange): void {
    // Check if changed
    if (this.filter.page_size === value) {
      return;
    }

    // Set filter properties
    this.filter.page_size = value;
    this.filter.page = 1;

    // Fetch projects with filter
    this.fetchProjects();
  }
  //-----------------------------------------------------------------------------------------------

  public onOrderingChange(ordering: string): void {
    const F = this.filter;

    // Set filter properties
    if (F.ordering === ordering) {
      if (F.asc) {
        F.asc = false;
      } else {
        F.ordering = '';
      }
    } else {
      F.asc = true;
      F.ordering = ordering;
    }
    // this.filter.page = 1;

    // Fetch projects with filter
    this.fetchProjects();
  }

  public onPageChange(pageNumber: number): void {
    // Check if changed
    // Ignore reflection of `this.filter.page = 1;` in other handlers
    if (this.filter.page === pageNumber) {
      return;
    }

    // Set filter properties
    this.filter.page = pageNumber;

    // Fetch projects with filter
    this.fetchProjects();
  }
}
