import { Component, OnInit, Input, Output, EventEmitter } from '@angular/core';


export type PageSizeRange = 5 | 20 | 50 | 'all';


@Component({
  selector: 'app-projects-filter',
  templateUrl: './projects-filter.component.html',
  styleUrls: ['./projects-filter.component.scss']
})
export class ProjectsFilterComponent implements OnInit {
  private dateErrorTimeout: any;

  public dateError: string;

  @Input() dateMessage: string;
  @Input() itemsCount: number;
  @Input() fromDate: string = '';
  @Input() toDate: string = '';
  @Input() search = '';
  @Input() pageSize: PageSizeRange = 20;

  @Output() dateChange = new EventEmitter<{ from: string, to: string }>();
  @Output() searchChange = new EventEmitter<string>();
  @Output() pageSizeChange = new EventEmitter<PageSizeRange>();


  constructor() { }

  ngOnInit() {
  }

  public submitDateFilter(): void {
    clearTimeout(this.dateErrorTimeout);
    this.dateError = null;

    // Check date validation
    const fromDate = new Date(this.fromDate);
    const toDate = new Date(this.toDate);
    if (fromDate.getTime() > toDate.getTime()) {
      this.dateError = '<strong>Error!</strong> To Date must be greater or equal to Form Date.';
      this.dateErrorTimeout = setTimeout(() => this.dateError = null, 5000);
      return;
    }

    // Send entered dates to parent component
    this.dateChange.emit({ from: this.fromDate, to: this.toDate });
  }

  public clearDateFilter(): void {
    this.dateError = null;
    this.fromDate = '';
    this.toDate = '';

    // Send empty dates to parent component
    this.dateChange.emit({ from: this.fromDate, to: this.toDate });
  }

  public onSearchChange(): void {
    this.search = this.search.trim();
    this.searchChange.emit(this.search);
  }

  public onPageSizeChange(): void {
    this.pageSizeChange.emit(this.pageSize);
  }
}
